        ManifestPath = $ManifestPath
        PolicyPath   = $PolicyPath
        Compliant    = ($denied -eq 0 -and $unknown -eq 0)
        Summary      = [pscustomobject]@{
            Total         = $rows.Count
            ApprovedCount = $approved
